import torch
import torch.nn as nn


class EnergyBasedModel(nn.Module):
    """Simple EBM: scalar energy E_θ(x), score = -∇_x E_θ(x)."""

    def __init__(self, input_dim: int, hidden_dim: int = 256):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(input_dim, hidden_dim), nn.SiLU(),
            nn.Linear(hidden_dim, hidden_dim), nn.SiLU(),
            nn.Linear(hidden_dim, 1),
        )

    def energy(self, x: torch.Tensor) -> torch.Tensor:
        return self.net(x).squeeze(-1)   # (B,)

    def score(self, x: torch.Tensor) -> torch.Tensor:
        """Score ∇_x log p = -∇_x E, computed via autograd."""
        x = x.requires_grad_(True)
        e = self.energy(x).sum()         # scalar for backward
        grad = torch.autograd.grad(e, x)[0]
        return -grad                     # (B, D)


class ScoreNetwork(nn.Module):
    """Direct score network s_θ(x) ≈ ∇_x log p(x), no energy formulation."""

    def __init__(self, input_dim: int, hidden_dim: int = 256):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(input_dim, hidden_dim), nn.SiLU(),
            nn.Linear(hidden_dim, hidden_dim), nn.SiLU(),
            nn.Linear(hidden_dim, input_dim),   # output shape matches x
        )

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        return self.net(x)   # (B, D) — same shape as x
